  ('aboriginal-6f0ba476-moex-00221', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '某律師事務所於X1年初預收客戶2年法律諮詢顧問費用，若X1年底未作應有之調整分錄，將 會對X1年財務報表造成何種影響？', '["資產高估", "負債高估", "收益高估", "費損高估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00222', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'A公司帳載現金餘額為$900,000，已知公司開立支付給供應商之支票，面額為$8,800，帳上卻誤植 為$9,800；銀行代收票據一紙$6,000，公司尚未入帳；在途存款$10,000；未兌現支票$80,000。則 正確的現金餘額應為何？', '["$907,000", "$905,000", "$917,000", "$890,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00223', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '關於零用金會計處理，下列敘述何者錯誤？', '["撥補零用金時，借記零用金", "使用零用金時，零用金保管人只須做備忘錄就可", "零用金期末發生現金短溢時，若「現金短溢」為借方餘額，則可列為其他費用", "期末結帳時，不管有無撥補零用金，已支出的費用仍須入帳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00224', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'A公司於2022年11月20日收到面額$4,000,000，利率6%，90天到期的本票，於12月20日向 銀行請求具追索權之貼現，利率為10%，試問12月20日的貼現分錄下列何者正確？（計算利息、 貼現息時，1年以360天計並計算至整數，小數點後第一位數四捨五入）', '["借記：現金$4,060,000", "借記：短期應收票據貼現折價$7,667", "貸記：應付利息$67,667", "貸記：利息收入$60,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00225', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司與A客戶簽訂銷貨合約，合約中約定每件售價$500，總銷售量600件，合約中並約定給A 客戶退貨權，允許客戶在30天內無條件退貨，且甲公司必須全額退費，每件商品的成本為$400。 假設此合約適用國際財務報導準則第15號有關客戶合約收入之規範，甲公司並以期望值50件為 退貨件數的估計值，該公司商品存貨會計處理採用永續盤存制，試問關於此銷貨合約的會計分錄 處理何者錯誤？', '["銷貨時，認列銷貨收入$300,000", "銷貨時，認列應收帳款$300,000", "銷貨時，認列退款負債$25,000", "銷貨時，認列銷貨成本$220,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00226', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司為一大盤批發商，於X1年5月1日賒銷貨品一批給乙公司，定價$450,000，商業折扣為 20%，信用條件為「3/10、n/30」。乙公司於X1年5月10日支付該筆款項之60%，餘款於X1年 5月29日付清。請問此交易甲公司共收到多少現金？', '["$349,200", "$353,520", "$360,000", "$450,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00227', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '期末存貨為$600,000時，存貨週轉天數（以360天計算）為225天，若期末存貨為$200,000則為 150天，期初存貨金額未知，試問銷貨成本為若干？', '["$600,000", "$800,000", "$960,000", "$560,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00228', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司X1年、X2年、X3年的稅前淨利分別為$800,000、$900,000、$1,000,000，若X1年底存貨 低估$20,000，X2年底存貨高估$10,000，X3年底存貨低估$25,000，請問乙公司X1年至X3年正 確的稅前淨利各應為何？', '["$800,000、$900,000、$1,000,000", "$780,000、$910,000、$1,025,000", "$820,000、$890,000、$1,025,000", "$820,000、$870,000、$1,035,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00229', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'A公司為家具經銷店，銷貨毛利率為銷貨淨額的40%，2023年4月底，A公司之倉庫遭竊，其4 月之存貨相關資訊如下：期初存貨$80,000；進貨淨額$400,000；銷貨淨額$300,000。遭竊隔天檢 查倉庫後，發現剩下一批售價為 $20,000之存貨完好無缺。若使用毛利率法，A公司之存貨因遭 竊所造成之損失為何？', '["$280,000", "$292,000", "$288,000", "$300,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
